    frases: [
      { pt: "Quanto custa?",           target: "Сколько стоит?",              phonetic: "[Skól'ko stóit?]",               example: "Сколько стоит этот билет?",       tip: "'Сколько стоят эти?' for plural items. 'Стоит' comes from 'стоить' (to cost)." },
      { pt: "Não entendo",             target: "Я не понимаю",                phonetic: "[Ya ne panimáyu]",               example: "Извините, я не понимаю по-русски.", tip: "Saying this with a smile goes a long way — Russians respect any attempt to use the language and become more patient." },
      { pt: "Pode repetir?",           target: "Повторите, пожалуйста",       phonetic: "[Pavtaríte, pojáluista]",        example: "Повторите медленнее, пожалуйста.", tip: "Formal imperative. Add 'помедленнее' [pomedlyenneye] = more slowly, or 'ещё раз' [yeshcho raz] = one more time." },
      { pt: "Onde fica o banheiro?",   target: "Где туалет?",                 phonetic: "[Gdye tualét?]",                 example: "Извините, где туалет?",            tip: "Short, direct and universally understood. 'Где' = where. One of the most essential phrases in any language." },
      { pt: "Estou com fome",          target: "Я голоден",                   phonetic: "[Ya gólayen]",                   example: "Я очень голоден, где ресторан?",  tip: "Masculine: 'голоден'. Feminine: 'голодна'. 'Ресторан' = restaurant." },
      { pt: "Me chamo...",             target: "Меня зовут...",               phonetic: "[Menya zavút...]",               example: "Меня зовут Карлос, приятно!",     tip: "Literally 'they call me...' (passive construction). 'Приятно' [priyatno] = pleased to meet you." },
      { pt: "Fala português?",         target: "Вы говорите по-португальски?",phonetic: "[Vi gavaríte pa-partugál'ski?]", example: "Вы говорите по-португальски?",    tip: "The pattern 'по-[language]' = in [language]: 'по-русски' = in Russian, 'по-английски' = in English." },
      { pt: "Preciso de ajuda",        target: "Мне нужна помощь",            phonetic: "[Mnye nujná pómash']",           example: "Помогите! Мне нужна помощь.",     tip: "'Помогите!' [pomogíte] = help me! (shout this in an emergency). 'Мне нужна' = I need (lit. to me needed)." },
      { pt: "Tudo bem?",               target: "Как дела?",                   phonetic: "[Kak delá?]",                    example: "Привет! Как дела? Всё хорошо?",  tip: "Standard answer: 'Хорошо, спасибо' = good, thanks. 'Нормально' [normalno] = fine/OK. Both are natural." },
      { pt: "Com licença!",            target: "Простите!",                   phonetic: "[Prostíte!]",                    example: "Простите, можно пройти?",         tip: "'Можно пройти?' = may I pass? A complete, polite phrase for squeezing past someone." },
      { pt: "Onde fica o hotel?",      target: "Где находится отель?",        phonetic: "[Gdye nakhóditsa otel'?]",       example: "Где находится гостиница Москва?", tip: "'Находится' = is located. More formal than just 'где отель?' but sounds more natural when asking directions." },
      { pt: "Pode me ajudar?",         target: "Вы можете мне помочь?",       phonetic: "[Vi mójete mnye pamóch'?]",      example: "Вы можете мне помочь с картой?",  tip: "Formal (Вы). With friends: 'Ты можешь мне помочь?' [ti mojesh mne pomoch']. Always polite with strangers." },
      { pt: "Não falo russo bem",      target: "Я плохо говорю по-русски",    phonetic: "[Ya plókho gavaryú pa-rúski]",   example: "Я плохо говорю по-русски, говорите медленнее.", tip: "Russians genuinely appreciate any effort with the language. This phrase opens doors and brings smiles." },
      { pt: "Qual é o seu nome?",      target: "Как вас зовут?",              phonetic: "[Kak vas zavút?]",               example: "Извините, как вас зовут?",        tip: "Formal (вас). Informal: 'Как тебя зовут?' [kak tebya zavut?]. Use вас with anyone you'd address respectfully." },
      { pt: "Estou perdido(a)",        target: "Я заблудился",                phonetic: "[Ya zabludílsya]",               example: "Я заблудился, где центр города?",  tip: "Masculine: 'заблудился'. Feminine: 'заблудилась' [zabludilas']. Russian streets can be confusing — this phrase is useful!" },
      { pt: "Chame a polícia!",        target: "Вызовите полицию!",           phonetic: "[Vízavite palítsyu!]",           example: "Помогите! Вызовите полицию!",     tip: "Emergency number in Russia: 102. 'Скорую!' [skoruyu] = call an ambulance! Also very useful to know." },
      { pt: "Que horas são?",          target: "Который час?",                phonetic: "[Katóry chas?]",                 example: "Который час? Опоздаю на поезд.",  tip: "'Час' = hour / 1 o'clock. 'Сейчас три часа' = it's three o'clock now." },
      { pt: "Tem Wi-Fi aqui?",         target: "Здесь есть Wi-Fi?",           phonetic: "[Zdes' yest' Wi-Fi?]",           example: "Здесь есть Wi-Fi? Какой пароль?", tip: "'Пароль' [parol'] = password. Russia has extensive Wi-Fi coverage in cities, cafés and the metro." },
      { pt: "A conta, por favor",      target: "Счёт, пожалуйста",            phonetic: "[Schyot, pojáluista]",           example: "Официант, счёт, пожалуйста!",    tip: "'Официант' [ofitsiánt] = waiter. In Russian restaurants you always need to ask for the bill — it won't arrive on its own." },
      { pt: "Posso pagar com cartão?", target: "Можно оплатить картой?",      phonetic: "[Mójno aplatít' kártay?]",       example: "Можно оплатить картой или только наличными?", tip: "'Наличные' [nalichniye] = cash. Card payment is widely accepted in Russian cities, but carry some cash for markets and small shops." },
    ],
